import { useState } from "react";
import { Scanner } from "@yudiel/react-qr-scanner";
import "./App.css";

function App() {
  const [cameraActive, setCameraActive] = useState(false);
  const [permissionAsked, setPermissionAsked] = useState(false);

  const [currentSong, setCurrentSong] = useState(null);
  const [pendingSong, setPendingSong] = useState(null);
  const [audioObj, setAudioObj] = useState(null);

  const startScanner = () => {
    setCameraActive(true);
    setPermissionAsked(true);
  };

  const handleScan = (results) => {
    if (results?.length > 0) {
      const qrValue = results[0]?.rawValue?.trim();
      if (qrValue && qrValue !== currentSong && qrValue !== pendingSong) {
        setPendingSong(qrValue);
        setCameraActive(false);
      }
    }
  };

  const playSong = (songName) => {
    if (audioObj) {
      audioObj.pause();
      audioObj.currentTime = 0;
    }

    const audio = new Audio(`/hitster/public/audio/${songName}.mp3`); // <<< ważne: /hitster/
    audio.loop = false;

    audio.play().catch((err) => {
      alert("Nie udało się odtworzyć piosenki: " + err.message);
    });

    setAudioObj(audio);
    setCurrentSong(songName);
    setPendingSong(null);
  };

  const startPlaying = () => {
    if (pendingSong) {
      playSong(pendingSong);
    }
  };

  const stopAndReturn = () => {
    if (audioObj) {
      audioObj.pause();
      audioObj.currentTime = 0;
      setAudioObj(null);
    }
    setCurrentSong(null);
    setPendingSong(null);
    setCameraActive(true);
  };

  return (
    <div className="app-container">
      <header className="App-header">

        {!permissionAsked && (
          <div className="start-screen">

            <button onClick={startScanner} className="start-btn">
              <span>Zaczynamy</span>
              <svg
                xmlns="http://www.w3.org/2000/svg"
                fill="none"
                viewBox="0 0 74 74"
                height="34"
                width="34"
              >
                <circle stroke-width="3" stroke="black" r="35.5" cy="37" cx="37"></circle>
                <path
                  fill="black"
                  d="M25 35.5C24.1716 35.5 23.5 36.1716 23.5 37C23.5 37.8284 24.1716 38.5 25 38.5V35.5ZM49.0607 38.0607C49.6464 37.4749 49.6464 36.5251 49.0607 35.9393L39.5147 26.3934C38.9289 25.8076 37.9792 25.8076 37.3934 26.3934C36.8076 26.9792 36.8076 27.9289 37.3934 28.5147L45.8787 37L37.3934 45.4853C36.8076 46.0711 36.8076 47.0208 37.3934 47.6066C37.9792 48.1924 38.9289 48.1924 39.5147 47.6066L49.0607 38.0607ZM25 38.5L48 38.5V35.5L25 35.5V38.5Z"
                ></path>
              </svg>
            </button>
          </div>
        )}

        {permissionAsked && !currentSong && !pendingSong && cameraActive && (
          <>
            <div className="scanner-box">
              <Scanner
                onScan={handleScan}
                styles={{
                  container: { width: "100%", maxWidth: "400px" },
                  video: { borderRadius: "12px" },
                }}
              />
            </div>
          </>
        )}

        {(pendingSong || currentSong) && (
          <div className="player-screen">
            <h2>{currentSong ? "Teraz gra:" : "Znaleziona piosenka:"}</h2>
            <h3
              style={{
                wordBreak: "break-all",
                margin: "20px 0",
                fontSize: "1.8em",
              }}
            >
              {pendingSong || currentSong}
            </h3>

            {pendingSong && (
              <button className="big-play-btn" onClick={startPlaying}>
                Odtwórz ▶
              </button>
            )}

            {currentSong && (
              <button className="stop-btn" onClick={stopAndReturn}>
                Stop i wróć do skanera
              </button>
            )}
          </div>
        )}
      </header>
    </div>
  );
}

export default App;
